// Migration 062 — image vulnerability reports + per-CVE rows, hand-authored
// sqlc shim.
//
// File suffix `_ext` is intentional: the canonical sqlc-CLI output for the
// image_vulns query group would land in internal/db/sqlc/image_vulns.sql.go,
// which is auto-regenerated by repo tooling. The CLI is broken in this repo
// at the moment, so we hand-roll the same shape here. The interface
// signatures match what `sqlc generate` would emit (Querier inclusion left
// out — the canonical Querier is generator-output, and adding hand entries
// there would be clobbered by the next regeneration).

package sqlc

import (
	"context"
	"time"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgtype"
)

// ----------------------------------------------------------------------
// Models — these are the Go-side mirrors of the DB rows. They live here
// (rather than in models.go) because models.go is generated.
// ----------------------------------------------------------------------

// ImageVulnerabilityReport mirrors a row of image_vulnerability_reports.
type ImageVulnerabilityReport struct {
	ID             uuid.UUID `json:"id"`
	ClusterID      uuid.UUID `json:"cluster_id"`
	ReportName     string    `json:"report_name"`
	Namespace      string    `json:"namespace"`
	WorkloadKind   string    `json:"workload_kind"`
	WorkloadName   string    `json:"workload_name"`
	ContainerName  string    `json:"container_name"`
	ImageRegistry  string    `json:"image_registry"`
	ImageRepo      string    `json:"image_repo"`
	ImageTag       string    `json:"image_tag"`
	ImageDigest    string    `json:"image_digest"`
	Scanner        string    `json:"scanner"`
	ScannerVersion string    `json:"scanner_version"`
	CriticalCount  int32     `json:"critical_count"`
	HighCount      int32     `json:"high_count"`
	MediumCount    int32     `json:"medium_count"`
	LowCount       int32     `json:"low_count"`
	UnknownCount   int32     `json:"unknown_count"`
	ScannedAt      time.Time `json:"scanned_at"`
	CreatedAt      time.Time `json:"created_at"`
	UpdatedAt      time.Time `json:"updated_at"`
}

// ImageVulnerability mirrors a row of image_vulnerabilities.
type ImageVulnerability struct {
	ID               uuid.UUID      `json:"id"`
	ReportID         uuid.UUID      `json:"report_id"`
	VulnerabilityID  string         `json:"vulnerability_id"`
	Severity         string         `json:"severity"`
	PkgName          string         `json:"pkg_name"`
	InstalledVersion string         `json:"installed_version"`
	FixedVersion     string         `json:"fixed_version"`
	PrimaryLink      string         `json:"primary_link"`
	CvssScore        pgtype.Numeric `json:"cvss_score"`
	Title            string         `json:"title"`
	Description      string         `json:"description"`
	CreatedAt        time.Time      `json:"created_at"`
}

// CVSSScoreFloat returns the typed score and ok=false when NULL. Helper
// for handlers/tests that want a plain float64 without re-implementing
// pgtype.Numeric decoding each time.
func (v ImageVulnerability) CVSSScoreFloat() (float64, bool) {
	if !v.CvssScore.Valid {
		return 0, false
	}
	f, err := v.CvssScore.Float64Value()
	if err != nil || !f.Valid {
		return 0, false
	}
	return f.Float64, true
}

