// ----------------------------------------------------------------------
// Aggregates — one row each, used by the cluster / fleet rollup
// endpoints. Returned as a typed struct so the JSON encoder produces a
// stable shape across binary releases.
// ----------------------------------------------------------------------

// AggregateClusterVulnerabilitiesRow is the projection used by both the
// per-cluster and per-fleet aggregate queries. We reuse the type so the
// handler-side rendering is symmetric.
type AggregateClusterVulnerabilitiesRow struct {
	Critical      int64              `json:"critical"`
	High          int64              `json:"high"`
	Medium        int64              `json:"medium"`
	Low           int64              `json:"low"`
	Unknown       int64              `json:"unknown"`
	ReportCount   int64              `json:"report_count"`
	LastScannedAt pgtype.Timestamptz `json:"last_scanned_at"`
}

const aggregateClusterVulnerabilities = `-- name: AggregateClusterVulnerabilities :one
SELECT
    COALESCE(SUM(critical_count), 0)::bigint AS critical,
    COALESCE(SUM(high_count), 0)::bigint AS high,
    COALESCE(SUM(medium_count), 0)::bigint AS medium,
    COALESCE(SUM(low_count), 0)::bigint AS low,
    COALESCE(SUM(unknown_count), 0)::bigint AS unknown,
    COUNT(*)::bigint AS report_count,
    MAX(scanned_at) AS last_scanned_at
FROM image_vulnerability_reports
WHERE cluster_id = $1`

func (q *Queries) AggregateClusterVulnerabilities(ctx context.Context, clusterID uuid.UUID) (AggregateClusterVulnerabilitiesRow, error) {
	var r AggregateClusterVulnerabilitiesRow
	err := q.db.QueryRow(ctx, aggregateClusterVulnerabilities, clusterID).Scan(
		&r.Critical, &r.High, &r.Medium, &r.Low, &r.Unknown,
		&r.ReportCount, &r.LastScannedAt,
	)
	return r, err
}

// AggregateFleetVulnerabilitiesRow extends the cluster row with the
// distinct-cluster count, used by the /security/vulnerabilities/summary/
// endpoint that operators with security:read can call.
type AggregateFleetVulnerabilitiesRow struct {
	Critical      int64              `json:"critical"`
	High          int64              `json:"high"`
	Medium        int64              `json:"medium"`
	Low           int64              `json:"low"`
	Unknown       int64              `json:"unknown"`
	ReportCount   int64              `json:"report_count"`
	ClusterCount  int64              `json:"cluster_count"`
	LastScannedAt pgtype.Timestamptz `json:"last_scanned_at"`
}

const aggregateFleetVulnerabilities = `-- name: AggregateFleetVulnerabilities :one
SELECT
    COALESCE(SUM(critical_count), 0)::bigint AS critical,
    COALESCE(SUM(high_count), 0)::bigint AS high,
    COALESCE(SUM(medium_count), 0)::bigint AS medium,
    COALESCE(SUM(low_count), 0)::bigint AS low,
    COALESCE(SUM(unknown_count), 0)::bigint AS unknown,
    COUNT(*)::bigint AS report_count,
    COUNT(DISTINCT cluster_id)::bigint AS cluster_count,
    MAX(scanned_at) AS last_scanned_at
FROM image_vulnerability_reports`

func (q *Queries) AggregateFleetVulnerabilities(ctx context.Context) (AggregateFleetVulnerabilitiesRow, error) {
	var r AggregateFleetVulnerabilitiesRow
	err := q.db.QueryRow(ctx, aggregateFleetVulnerabilities).Scan(
		&r.Critical, &r.High, &r.Medium, &r.Low, &r.Unknown,
		&r.ReportCount, &r.ClusterCount, &r.LastScannedAt,
	)
	return r, err
}

// TopClustersByVulnerabilityRow is one cluster's roll-up of its image
// scan posture. The "critical+high" tuple is the de-facto operator
// "worst clusters" ranking on the /dashboard/security/ page.
type TopClustersByVulnerabilityRow struct {
	ClusterID     uuid.UUID          `json:"cluster_id"`
	Critical      int64              `json:"critical"`
	High          int64              `json:"high"`
	Medium        int64              `json:"medium"`
	Low           int64              `json:"low"`
	ReportCount   int64              `json:"report_count"`
	LastScannedAt pgtype.Timestamptz `json:"last_scanned_at"`
}

const topClustersByVulnerability = `-- name: TopClustersByVulnerability :many
SELECT
    cluster_id,
    COALESCE(SUM(critical_count), 0)::bigint AS critical,
    COALESCE(SUM(high_count), 0)::bigint AS high,
    COALESCE(SUM(medium_count), 0)::bigint AS medium,
    COALESCE(SUM(low_count), 0)::bigint AS low,
    COUNT(*)::bigint AS report_count,
    MAX(scanned_at) AS last_scanned_at
FROM image_vulnerability_reports
GROUP BY cluster_id
ORDER BY critical DESC, high DESC
LIMIT $1`

func (q *Queries) TopClustersByVulnerability(ctx context.Context, limit int32) ([]TopClustersByVulnerabilityRow, error) {
	rows, err := q.db.Query(ctx, topClustersByVulnerability, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []TopClustersByVulnerabilityRow{}
	for rows.Next() {
		var r TopClustersByVulnerabilityRow
		if err := rows.Scan(
			&r.ClusterID, &r.Critical, &r.High, &r.Medium, &r.Low,
			&r.ReportCount, &r.LastScannedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, r)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

